import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Setting Up IntelliJ IDEA","description":"A step-by-step guide on how to set up IntelliJ IDEA to create mods using Fabric.","frontmatter":{"title":"Setting Up IntelliJ IDEA","description":"A step-by-step guide on how to set up IntelliJ IDEA to create mods using Fabric.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","dicedpixels","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"prev":{"text":"Setting Up Your IDE","link":"../setting-up"},"next":{"text":"Opening a Project in IntelliJ IDEA","link":"./opening-a-project"},"files":[]},"headers":[],"relativePath":"1.21.8/develop/getting-started/intellij-idea/setting-up.md","filePath":"versions/1.21.8/develop/getting-started/intellij-idea/setting-up.md","lastUpdated":1760721669000}`);var o={name:`1.21.8/develop/getting-started/intellij-idea/setting-up.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Setting Up IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Setting Up IntelliJ IDEA”">​</a></h1><div class="info custom-block"><p class="custom-block-title">PREREQUISITES</p><p>Make sure you&#39;ve <a href="./../setting-up#install-jdk-21">installed a JDK</a> first.</p></div><h2 id="installing-intellij-idea" tabindex="-1">Installing IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Installing IntelliJ IDEA”">​</a></h2><p>If you do not have IntelliJ IDEA installed, you can download it from the <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">official website</a> - follow the installation steps for your operating system.</p><p>The Community edition of IntelliJ IDEA is free and open-source, and it is the recommended version for modding with Fabric.</p><div class="info custom-block"><p class="custom-block-title">DOWNLOADS</p><p>You may have to scroll down to find the Community edition download link.</p></div><p><img src="/assets/develop/getting-started/idea-community.png" alt="IDEA Community Edition Download Prompt" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Installing &quot;Minecraft Development&quot; Plugin <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Installing &quot;Minecraft Development&quot; Plugin”">​</a></h2><p>The Minecraft Development plugin provides support for modding with Fabric, and it is the most important plugin to install.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Although this plugin isn&#39;t strictly necessary, it can make modding with Fabric much easier - you should consider installing it.</p></div><p>You can install it by opening IntelliJ IDEA, and then navigating to <strong>File</strong> &gt; <strong>Settings</strong> &gt; <strong>Plugins</strong> &gt; <strong>Marketplace</strong> tab, then search for <code>Minecraft Development</code> in the search bar, and click the <strong>Install</strong> button.</p><p>Alternatively, you can download it from the <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">plugin page</a> and then install it by navigating to <strong>File</strong> &gt; <strong>Settings</strong> &gt; <strong>Plugins</strong> &gt; <strong>Install Plugin From Disk</strong>.</p><h3 id="about-creating-a-project" tabindex="-1">About Creating a Project <a class="header-anchor" href="#about-creating-a-project" aria-label="Permalink to “About Creating a Project”">​</a></h3><p>While it is possible to create a project using this plugin, this is not recommended because the templates are often out of date. Instead, consider following <a href="./../creating-a-project">Creating a Project</a> to use the Fabric Template Mod Generator.</p>`,14)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};